(6010, 'Agenda culturel des vallées d''Aure et du Louron', 17527, 'agenda-culturel-aure-louron', 'Cliquez sur chaque événement pour obtenir plus d''informations!', 'review_animations-en-vallees-d-aure-et-du-louron_00.jpg', '', 0, '2016-05-18 09:34:39', '2016-10-14 13:49:51', 44231860, 0, '{"order":"relative","moderated":false,"send_invitation_email":true,"contributorconfigstep":-1,"cFields":{"organization":[],"contact_number":[],"contact_name":[],"email":[]}}', 1, 'INFO\r\n\r\nSi vous souhaitez créer un nouveau lieu :\r\n- cliquez sur "Ajouter un lieu"\r\n- remplissez le champ "nom du lieu" de manière précise (ex: église de Bourisp, salle des fêtes de Cadeilhan...)\r\n- remplissez le champ "adresse" avec le nom du village puis attendez quelques secondes afin que le lieu soit géolocalisé sur la carte. S''il cela ne marche pas, précisez un code postal.\r\n- cliquez sur "créer"\r\n\r\n', NULL, NULL, NULL),
